  ('heelevel3-e0adf6cd-moex-00160', 'heelevel3-e0adf6cd', 'heelevel3-e0adf6cd-moex-111-e0de6eb7', 'sub-heelevel3-e0adf6cd-05', NULL, 'essay', 'OECD於2008年啟動ProgrammefortheInternationalAssessmentofAdult
